date_order = datetime.date.today()
date_lock = timezone('Asia/Ho_Chi_Minh').localize(datetime.datetime.combine(date_order,datetime.time.min)).astimezone(timezone('UTC')).replace(tzinfo=None)
for company in env['res.company'].search([]):
    if company.po_lock_from_date_approve:
        before_approve = date_lock - datetime.timedelta(days=company.po_lock_from_date_approve)
        orders = env['purchase.order'].search([('company_id','=',company.id),('state','=','purchase'),('date_approve','<',before_approve),('picking_ids','!=',False),('picking_ids','not any',[('state','=','done')])])
        if orders:orders.button_done()
    if company.po_lock_from_date_receipt:
        before_receipt = date_lock - datetime.timedelta(days=company.po_lock_from_date_receipt)
        orders = env['purchase.order'].search([('company_id','=',company.id),('state','=','purchase'),('ttb_receipt_date','<=',before_receipt),('picking_ids','!=',False),('picking_ids','any',[('state','=','done')]),('picking_ids','any',[('state','!=','done')])])
        if orders:orders.button_done()
